      });
    } catch (error) {
      console.error('Error deleting channel:', error);
      throw error;
    }
  }

  // Games
  async getGames(): Promise<Game[]> {
    try {
      const response = await axios.get(`${this.baseURL}/games`, {
        headers: this.getHeaders()
      });
      return response.data;
    } catch (error) {
